function validateForm(){const e=document.getElementById("pickupAddress").value.trim(),t=document.getElementById("dropoffAddress").value.trim(),n=document.getElementById("passengers").value;return e.length<3?(alert("Please enter a valid pickup location."),document.getElementById("pickupAddress").focus(),!1):t.length<3?(alert("Please enter a valid drop-off location."),document.getElementById("dropoffAddress").focus(),!1):!(!n||Number(n)<1)||(alert("Please enter the number of passengers."),document.getElementById("passengers").focus(),!1)}function trackGoogleAdsConversion(){}document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("bookingForm");e&&e.addEventListener("submit",t=>{t.preventDefault();const n=document.getElementById("submitBtn");if(!validateForm())return;const o=n.innerText;n.disabled=!0,n.innerText="Sending…";const r=new FormData(e);fetch("https://formsubmit.co/41757e77266e7223e0b126c967d36688",{method:"POST",headers:{Accept:"application/json"},body:r}).then(e=>e.json()).then(()=>{trackGoogleAdsConversion(),alert("✅ Your quote request has been sent! We will contact you shortly."),e.reset()}).catch(()=>{alert("Your request may have been sent. If urgent, please call us at 0301-1954994.")}).finally(()=>{n.disabled=!1,n.innerText=o})}),document.querySelectorAll(".book-btn").forEach(e=>{e.addEventListener("click",()=>{document.getElementById("quoteForm").scrollIntoView({behavior:"smooth"})})})});